import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        Node left, right;
    }
    static boolean isMirror(Node a, Node b) {
        if (a == null && b == null) return true;
        if (a == null || b == null) return false;
        return isMirror(a.left, b.right) && isMirror(a.right, b.left);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> child = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                Node parent = map.computeIfAbsent(p, k -> new Node());
                Node childNode = map.computeIfAbsent(c, k -> new Node());
                if (dir == 'L') parent.left = childNode; else parent.right = childNode;
                child.add(c);
            }
            int rootId = -1;
            for (int id : map.keySet()) {
                if (!child.contains(id)) { rootId = id; break; }
            }
            Node root = (rootId == -1) ? null : map.get(rootId);
            if (root == null || isMirror(root.left, root.right)) out.append("YES\n");
            else out.append("NO\n");
        }
        System.out.print(out.toString());
    }
}

